import { Link } from 'react-router-dom';
import { useState } from 'react';
import leadService from '../services/leadService';

export default function Hero() {
  const trustBadges = [
    { icon: '✓', text: 'Obligatoire en France' },
    { icon: '⚖', text: 'Loi Spinetta' },
    { icon: '⚡', text: 'Devis rapide' },
  ];

  const [formData, setFormData] = useState({ name: '', email: '', phone: '', company: '', status: '' });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsSubmitting(true);
    try {
      await leadService.createLead(formData);
      setIsSuccess(true);
    } catch (err) {
      console.error(err);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <section className="relative bg-gradient-to-br from-blue-900 via-blue-800 to-blue-900 text-white pt-28 pb-20 md:pt-32 md:pb-28 overflow-hidden">
      <div className="absolute inset-0 bg-[url('data:image/svg+xml;base64,')] opacity-30"></div>

      <div className="relative max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="grid lg:grid-cols-2 gap-12 lg:gap-16 items-center">
          <div className="text-center lg:text-left">
            <h1 className="text-3xl sm:text-4xl md:text-5xl lg:text-6xl font-bold leading-tight">
              Assurance Décennale Électricien :{' '}
              <span className="text-gray-400">Comparez et Souscrivez</span>
            </h1>
            <p className="mt-6 text-lg sm:text-xl text-blue-100 max-w-xl mx-auto lg:mx-0">
              L'assurance décennale est obligatoire pour tout électricien selon la loi Spinetta. 
              Protégez votre activité pendant 10 ans avec notre protection RC Pro incluse.
            </p>

            <div className="mt-8 flex flex-col sm:flex-row gap-4 justify-center lg:justify-start">
              <Link to="/#quote" className="btn-primary text-lg px-8 py-4">
                Comparer les offres
              </Link>
              <Link to="/#features" className="btn-secondary border-white text-white hover:bg-white/10 px-8 py-4">
                Voir les garanties
              </Link>
            </div>

            <div className="mt-10 flex flex-wrap justify-center lg:justify-start gap-6">
              {trustBadges.map((badge, index) => (
                <div key={index} className="flex items-center gap-2 text-sm">
                  <span className="text-gray-400 text-lg">{badge.icon}</span>
                  <span className="text-blue-100">{badge.text}</span>
                </div>
              ))}
            </div>
          </div>

          <div className="hidden lg:block">
            <div className="relative">
              <div className="absolute -inset-4 bg-gray-400/20 rounded-3xl blur-2xl"></div>
              <div className="relative bg-white text-gray-900 p-6 rounded-2xl shadow-2xl">
                {isSuccess ? (
                  <div className="text-center py-8">
                    <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-4">
                      <svg className="w-8 h-8 text-green-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                      </svg>
                    </div>
                    <h3 className="text-xl font-bold text-gray-900 mb-2">Merci !</h3>
                    <p className="text-gray-600 text-sm">
                      Un expert vous contactera sous 24h pour votre devis personnalisé.
                    </p>
                  </div>
                ) : (
                  <>
                    <h3 className="text-lg font-bold mb-4">Devis gratuit</h3>
                    <form onSubmit={handleSubmit} className="space-y-3">
                      <input type="text" name="name" placeholder="Nom complet" value={formData.name} onChange={handleChange} required className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm" />
                      <input type="email" name="email" placeholder="Email" value={formData.email} onChange={handleChange} required className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm" />
                      <input type="tel" name="phone" placeholder="Téléphone" value={formData.phone} onChange={handleChange} required className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm" />
                      <input type="text" name="company" placeholder="Entreprise (optionnel)" value={formData.company} onChange={handleChange} className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm" />
                      <select name="status" value={formData.status} onChange={handleChange} required className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm">
                        <option value="">Statut...</option>
                        <option value="auto-entrepreneur">Auto-entrepreneur</option>
                        <option value="artisan">Artisan</option>
                        <option value="sarl">SARL</option>
                        <option value="eurl">EURL</option>
                      </select>
                      <button type="submit" disabled={isSubmitting} className="w-full bg-gray-700 hover:bg-gray-800 text-white font-bold py-2 px-4 rounded-lg transition-colors disabled:opacity-50 text-sm">
                        {isSubmitting ? 'Envoi...' : 'Obtenir mon devis'}
                      </button>
                    </form>
                    <p className="text-xs text-gray-500 mt-3 text-center">🔒 Vos données sont protégées</p>
                  </>
                )}
              </div>
            </div>
          </div>
        </div>
      </div>

      <div className="absolute bottom-0 left-0 right-0 h-24 bg-gradient-to-t from-white to-transparent"></div>
    </section>
  );
}
